if (!path.includes("[")) {
	// Concrete path — try pattern matching directly
	for (const pr of patterns) {
		const params = matchPattern(pr.compiled, path);
		if (params) {
			const resolved = interpolateDestination(pr.destination, params);
			return { destination: resolved, id: pr.id };
		}
	}
} else {
	// Template string — generate representative paths and test against patterns
	const representatives = generateRepresentatives(path, edges);
	for (const pr of patterns) {
		for (const rep of representatives) {
			const params = matchPattern(pr.compiled, rep);
			if (params) {
				const resolved = interpolateDestination(pr.destination, params);
				return { destination: resolved, id: pr.id };
			}
		}
	}
}

if (streaming) {
	// isNode is true in Deno node-compat mode but response construction from
	// async iterables is not supported, so we fall back to ReadableStream if isDeno is true.
	if (isNode && !isDeno) {
		const nodeBody = await renderToAsyncIterable(
			result,
			componentFactory,
			props,
			children,
			true,
			route,
		);
		// Node.js allows passing in an AsyncIterable to the Response constructor.
		// This is non-standard so using `any` here to preserve types everywhere else.
		body = nodeBody as any;
	} else {
		body = await renderToReadableStream(result, componentFactory, props, children, true, route);
	}
} else {
	body = await renderToString(result, componentFactory, props, children, true, route);
}

if (await askToContinue({ flags, logger })) {
	const spinner = clack.spinner({ withGuide: false });
	spinner.start('Installing dependencies...');
	try {
		await exec(installCommand.command, [...installCommand.args, ...installSpecifiers], {
			nodeOptions: {
				cwd,
				// reset NODE_ENV to ensure install command run in dev mode
				env: { NODE_ENV: undefined },
			},
		});
		spinner.stop('Dependencies installed.');
		return 'updated';
	} catch (err: any) {
		spinner.error('Error installing dependencies.');
		logger.debug('add', 'Error installing dependencies', err);
		// NOTE: `err.stdout` can be an empty string, so log the full error instead for a more helpful log
		console.error('\n', err.stdout || err.message, '\n');
		return 'failure';
	}
} else {
	return 'cancelled';
}

if (!parsedData.success) {
	const issue = parsedData.error.issues[0] as z.core.$ZodIssueInvalidUnion;

	// Due to this being a union, zod will always throw an "Expected array, received object" error along with the other errors.
	// This error is in the second position if the data is an array, and in the first position if the data is an object.
	const parseIssue = Array.isArray(unsafeData) ? issue.errors[0] : issue.errors[1];

	const error = parseIssue[0];
	const firstPathItem = error.path[0];

	const entry = Array.isArray(unsafeData)
		? unsafeData[firstPathItem as number]
		: unsafeData[firstPathItem as string];

	throw new AstroError({
		...AstroErrorData.ContentLoaderReturnsInvalidId,
		message: AstroErrorData.ContentLoaderReturnsInvalidId.message(context.collection, entry),
	});
}

try {
	transformResult = await compile(compileProps);
	// Compile all TypeScript to JavaScript.
	// Also, catches invalid JS/TS in the compiled output before returning.
	esbuildResult = await transformWithEsbuild(transformResult.code, compileProps.filename, {
		...compileProps.viteConfig.esbuild,
		loader: 'ts',
		sourcemap: 'external',
		tsconfigRaw: {
			compilerOptions: {
				// Ensure client:only imports are treeshaken
				verbatimModuleSyntax: false,
				importsNotUsedAsValues: 'remove',
			},
		},
	});
} catch (err: any) {
	await enhanceCompileError({
		err,
		id: compileProps.filename,
		source: compileProps.source,
		config: compileProps.astroConfig,
		logger: logger,
	});
	throw err;
}

for (const { node, language, grandParent, parent } of nodes) {
	const meta = (node.data as any)?.meta ?? node.properties.metastring ?? undefined;
	const code = toText(node, { whitespace: 'pre' });
	const result = await highlighter(code, language, { meta });

	let replacement: Element;
	if (typeof result === 'string') {
		// The replacement returns a root node with 1 child, the `<pre>` element replacement.
		replacement = fromHtml(result, { fragment: true }).children[0] as Element;
		// We just generated this node, so any positional information is invalid.
		removePosition(replacement);
	} else {
		replacement = result.children[0] as Element;
	}

	// We replace the parent in its parent with the new `<pre>` element.
	const index = grandParent.children.indexOf(parent);
	grandParent.children[index] = replacement;
}

const translationsCommand = defineCommand({
	meta: { name: "translations", description: "List translations for a content item" },
	args: {
		collection: {
			type: "positional",
			description: "Collection slug",
			required: true,
		},
		id: {
			type: "positional",
			description: "Content item ID or slug",
			required: true,
		},
		...connectionArgs,
	},
	async run({ args }) {
		configureOutputMode(args);
		try {
			const client = createClientFromArgs(args);
			const translations = await client.translations(args.collection, args.id);
			output(translations, args);
		} catch (error) {
			consola.error(error instanceof Error ? error.message : "Unknown error");
			process.exit(1);
		}
	},
});

try {
	if (this.#fetchHandler instanceof DefaultFetchHandler) {
		// Fast path: pass options directly, skip Reflect.set/get round-trip
		Reflect.set(request, appSymbol, this);
		response = await this.#fetchHandler.renderWithOptions(request, resolvedOptions);
	} else {
		// User-provided fetch handler: stamp options + app on the request
		setRenderOptions(request, resolvedOptions);
		Reflect.set(request, appSymbol, this);
		response = await this.#fetchHandler.fetch(request);
	}
} catch (err: any) {
	// Multi-level encoding (e.g., %2561 → %61) is rejected during URL
	// normalization in FetchState. Return 400 without rendering an error page.
	if (err instanceof MultiLevelEncodingError) {
		return new Response('Bad Request', { status: 400 });
	}
	throw err;
}

for (const message of batch.messages) {
	const job = message.body;
	try {
		const result = await processBackfillJob(job, deps);
		console.log("[aggregator] backfill job complete", {
			did: result.did,
			collection: result.collection,
			enqueued: result.enqueued,
		});
		message.ack();
	} catch (err) {
		// Resolution failures, listRecords 5xx, timeouts, and pagination
		// runaway all land here. Retry — Cloudflare Queues backoff handles
		// transient PDS failures; permanently broken DIDs land in the DLQ
		// after max_retries.
		console.error("[aggregator] backfill job failed, retrying", {
			did: job.did,
			collection: job.collection,
			error: formatErrorChain(err),
		});
		message.retry();
	}
}

for (const icon of icons) {
	let glyph: Glyph;

	try {
		// Find the glyph matching the icon name.
		glyph = font.nameToGlyph(icon);
	} catch {
		// If the glyph is not found, this means that multiple icons share the same glyph and we have
		// a mapping for such case.
		const alias = getFontGlyphAlias(icon);

		// When an alias is found, we update the definitions to use the alias instead of the original
		// icon name and continue to the next icon as there is no need to extract an SVG.
		updateDefinitionsWithAlias(definitions, icon, alias);
		continue;
	}

	// We need to compute various metrics to ensure the icon properly fits the viewBox size.
	const { fontSize, offsetX, offsetY } = getComputedFontSizeToFit(
		glyph,
		starlight.iconViewBoxSize
	);
	const path = glyph.getPath(offsetX, offsetY, fontSize);
	const iconName = getSetiIconName(icon);
	iconSvgs[iconName] = path.toSVG(pathDecimalPrecision);
}

return async (context) => {
	// Create a Context with the current Astro API context
	const localsContext = Context.make(AstroAPIContext, context);
	try {
		let _request = context.request;

		// Check if the URL contains '%40' and decode it to '@'
		// This is necessary for scoped package names in URLs
		// Effect HttpApi does not automatically decode '%40' to '@'
		if (_request.url.includes('/%40')) {
			_request = decodeRequestUrl(_request);
		}

		// Update the context request with the potentially modified request
		context.request = _request;

		// Handle the request using the generated handler
		return await handler(_request, localsContext);
	} catch (error) {
		// Log and rethrow any errors that occur during request handling
		console.error('Error handling request:', error);
		return new Response('Internal Server Error', { status: 500 });
	}
};
